import React, { useState, useEffect } from 'react';
import { getNotifications, markNotificationAsRead, getUserWaitingList, claimBook } from '../api/api';

function Notifications({ currentUserId }) {
  const [notifications, setNotifications] = useState([]);
  const [notifiedEntries, setNotifiedEntries] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ text: '', isError: false });

  const fetchData = async () => {
    setLoading(true);
    try {
      const notifRes = await getNotifications(currentUserId);
      setNotifications(notifRes.data);

      const waitlistRes = await getUserWaitingList(currentUserId);
      const notified = waitlistRes.data.filter(entry => entry.status === 'NOTIFIED');
      setNotifiedEntries(notified);
    } catch (error) {
      console.error("Error fetching notification page data:", error);
      showMessage("Failed to load notifications.", true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [currentUserId]);

  const showMessage = (text, isError = false) => {
    setMessage({ text, isError });
    setTimeout(() => setMessage({ text: '', isError: false }), 5000);
  };

  const handleMarkAsRead = async (notificationId) => {
    try {
      await markNotificationAsRead(notificationId);
      fetchData();
    } catch (error) {
      console.error("Error marking notification as read:", error);
    }
  };

  const handleClaim = async (entryId, bookTitle) => {
    try {
      await claimBook(entryId);
      showMessage(`Successfully claimed '${bookTitle}'! The book is now checked out to you.`, false);
      fetchData();
    } catch (error) {
      const errMsg = error.response?.data?.error || "Failed to claim book.";
      showMessage(errMsg, true);
    }
  };

  const getNotificationTypeLabel = (type) => {
    switch (type) {
      case 'DUE_REMINDER':
        return <span className="badge badge-warning">Due Date Reminder</span>;
      case 'FINE_UPDATE':
        return <span className="badge badge-danger">Fine Charge</span>;
      case 'BOOK_AVAILABLE':
        return <span className="badge badge-success">Book Available</span>;
      default:
        return <span className="badge badge-info">{type}</span>;
    }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h2>Notifications & Alerts</h2>
        <span>Active User ID: <strong>{currentUserId}</strong></span>
      </div>

      {message.text && (
        <div className={`alert-box ${message.isError ? 'alert-error' : 'alert-success'}`}>
          {message.text}
        </div>
      )}

      {loading ? (
        <p>Loading alerts...</p>
      ) : (
        <>
          {/* Actionable Reservations Section */}
          {notifiedEntries.length > 0 && (
            <div style={{ marginBottom: '30px', border: '1px solid #2ecc71', padding: '20px', borderRadius: '4px', backgroundColor: '#f9fffb' }}>
              <h3 style={{ color: '#27ae60', marginTop: 0 }}>🎉 Pending Reservations (Action Required)</h3>
              <p style={{ fontSize: '14px', color: '#555' }}>
                The following books on your waiting list are ready. Claim them within 24 hours of notification to borrow them.
              </p>
              <table style={{ margin: 0, backgroundColor: 'white' }}>
                <thead>
                  <tr>
                    <th>Book Title</th>
                    <th>Notified At</th>
                    <th>Claim Deadline</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {notifiedEntries.map((entry) => (
                    <tr key={entry.id}>
                      <td><strong>{entry.bookTitle}</strong></td>
                      <td>{new Date(entry.notifiedAt).toLocaleString()}</td>
                      <td style={{ color: '#e74c3c', fontWeight: 'bold' }}>
                        {new Date(entry.claimDeadline).toLocaleString()}
                      </td>
                      <td>
                        <button
                          className="btn btn-success btn-sm"
                          onClick={() => handleClaim(entry.id, entry.bookTitle)}
                        >
                          Claim & Borrow Now
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Notifications List */}
          <h3>System Messages</h3>
          <button className="btn btn-secondary btn-sm" onClick={fetchData} style={{ marginBottom: '15px' }}>
            🔄 Refresh List
          </button>

          {notifications.length === 0 ? (
            <p>You have no notifications.</p>
          ) : (
            <div className="notification-list">
              {notifications.map((notif) => (
                <div
                  key={notif.id}
                  className={`notification-item ${!notif.isRead ? 'unread' : ''}`}
                  onClick={() => !notif.isRead && handleMarkAsRead(notif.id)}
                >
                  <div className="notification-content">
                    <div style={{ marginBottom: '5px' }}>
                      {getNotificationTypeLabel(notif.type)}
                      <span className="notification-time" style={{ marginLeft: '10px' }}>
                        {new Date(notif.createdAt).toLocaleString()}
                      </span>
                    </div>
                    <div>{notif.message}</div>
                  </div>
                  <div className="notification-meta">
                    {!notif.isRead ? (
                      <span className="badge badge-info" style={{ cursor: 'pointer' }}>Mark Read</span>
                    ) : (
                      <span className="badge" style={{ backgroundColor: '#eee', color: '#aaa' }}>Read</span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}

export default Notifications;
